android.extraProguardRules:
-keepattributes Signature, *Annotation*, SourceFile, LineNumberTable, EnclosingMethod, InnerClasses, Exceptions
-renamesourcefileattribute SourceFile

# React Native + Hermes
-keep class com.facebook.react.turbomodule.** { *; }
-keep class com.facebook.hermes.** { *; }
-keep class com.facebook.jni.** { *; }
-dontwarn com.facebook.react.**

# Reanimated + Worklets
-keep class com.swmansion.reanimated.** { *; }
-keep class com.swmansion.worklets.** { *; }

# Expo modules (autolinked)
-keep class expo.modules.** { *; }
-keep class org.unimodules.** { *; }
-dontwarn expo.modules.**

# MapLibre — uses reflection for style/source/layer JSON binding
-keep class org.maplibre.** { *; }
-keep class com.mapbox.** { *; }
-dontwarn org.maplibre.**

# Sentry — needs original class names in stack traces
-keep class io.sentry.** { *; }
-dontwarn io.sentry.**

# PostHog
-keep class com.posthog.** { *; }
-dontwarn com.posthog.**

# OkHttp / Okio (used by Supabase + most networking)
-dontwarn okhttp3.**
-dontwarn okio.**
-dontwarn org.conscrypt.**

# Kotlin metadata
-keep class kotlin.Metadata { *; }
-keep class kotlinx.coroutines.** { *; }
-dontwarn kotlin.**
-dontwarn kotlinx.**

# Retain enum values() / valueOf() across the app (Zustand-style stores serialize them)
-keepclassmembers enum * {
    public static **[] values();
    public static ** valueOf(java.lang.String);
}

# Native methods + Parcelable Creator
-keepclasseswithmembernames class * { native <methods>; }
-keepclassmembers class * implements android.os.Parcelable {
    public static final android.os.Parcelable$Creator CREATOR;
}

# Strip verbose JS-bridge logs from release builds
-assumenosideeffects class android.util.Log {
    public static *** v(...);
    public static *** d(...);
    public static *** i(...);
}
